export const questions: Question[] = seeds.map((seed, index) => {
  const id = `q${String(index + 1).padStart(3, "0")}`;
  const choices = seed.choices.map((text, choiceIndex) => ({
    id: `${id}-${String.fromCharCode(97 + choiceIndex)}`,
    text,
  }));
  const correctChoiceId = choices[seed.correctIndex].id;

  return {
    id,
    moduleId: seed.moduleId,
    moduleName: getModuleName(seed.moduleId),
    topic: seed.topic,
    difficulty: seed.difficulty,
    questionType: seed.questionType,
    questionText: seed.questionText,
    choices,
    correctChoiceId,
    explanation: seed.explanation,
    whyWrong: Object.fromEntries(
      choices
        .filter((choice) => choice.id !== correctChoiceId)
        .map((choice) => [choice.id, `This choice does not address the core ${seed.topic.toLowerCase()} principle tested by the question.`]),
    ),
    examTrap: seed.examTrap,
    studyTip: seed.studyTip,
  };
});